mapper.insert:
INSERT IGNORE INTO bluenote_rank.rank_period (
    id, rank_code, period_id, period_type, period_status,
    start_at, end_at, frozen_at, created_at, updated_at
) VALUES (
    #{id}, #{rankCode}, #{periodId}, #{periodType}, #{periodStatus},
    #{startAt}, #{endAt}, #{frozenAt}, #{createdAt}, #{updatedAt}
)

mapper.select:
SELECT id, rank_code, period_id, period_type, period_status,
       start_at, end_at, frozen_at, created_at, updated_at
FROM bluenote_rank.rank_period
WHERE rank_code = #{rankCode}
  AND period_id = #{periodId}
